class Solution {
    public int minSwaps(String s) {
        int n = s.length();
        int[] count = new int[2];
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '[') {
                count[0]++;
            } else if (s.charAt(i) == ']') {
                count[1]--;
            }
        }
        int swaps = 0;
        while (count[0] != count[1]) {
            if (count[0] > count[1]) {
                swap(count);
                swaps++;
            }
        }
        return swaps;
    }

    public static void swap(int[] array) {
        int temp = array[0];
        array[0] = array[1];
        array[1] = temp;
    }
}
